```protobuf
syntax = "proto3";
package user;

option java_multiple_files = true;
option java_package = "com.maum.backend.protobuf.user";

service UserService {
  rpc Follow(FollowRequest) returns (FollowResponse);
  rpc Unfollow(UnfollowRequest) returns (UnfollowResponse);
  rpc IsFollowing(IsFollowingRequest) returns (IsFollowingResponse);
  rpc GetFollowers(GetFollowersRequest) returns (GetFollowersResponse);
  rpc GetFollowings(GetFollowingsRequest) returns (GetFollowingsResponse);
  rpc GetFollowerCount(GetFollowerCountRequest) returns (GetFollowerCountResponse);
  rpc GetFollowingCount(GetFollowingCountRequest) returns (GetFollowingCountResponse);
}

message FollowRequest {
  string user_id = 1;
  string target_user_id = 2;
}

message FollowResponse {
  string id = 1;
  string follower_id = 2;
  string following_id = 3;
  string status = 4;
  string created_at = 5;
}

message UnfollowRequest {
  string user_id = 1;
  string target_user_id = 2;
}

message UnfollowResponse {
  bool success = 1;
}

message IsFollowingRequest {
  string user_id = 1;
  string target_user_id = 2;
}

message IsFollowingResponse {
  bool is_following = 1;
}

message GetFollowersRequest {
  string user_id = 1;
  int32 limit = 2;
  int32 offset = 3;
}

message GetFollowersResponse {
  repeated SimpleUser followers = 1;
  int64 total = 2;
}

message GetFollowingsRequest {
  string user_id = 1;
  int32 limit = 2;
  int32 offset = 3;
}

message GetFollowingsResponse {
  repeated SimpleUser followings = 1;
  int64 total = 2;
}

message GetFollowerCountRequest {
  string user_id = 1;
}

message GetFollowerCountResponse {
  int64 count = 1;
}

message GetFollowingCountRequest {
  string user_id = 1;
}

message GetFollowingCountResponse {
  int64 count = 1;
}

message SimpleUser {
  string id = 1;
  string name = 2;
  string profile_image = 3;
}
