## 5. gRPC 서비스 구현 (user 모듈)

**파일 경로:** `/user/src/main/kotlin/com/maum/backend/controller/UserGrpcService.kt`

```kotlin
@GrpcService
class UserGrpcService(
    private val userService: UserService,
    private val userRepository: UserRepository,
) : UserServiceGrpc.UserServiceImplBase() {

    override fun follow(
        request: FollowRequest,
        responseObserver: StreamObserver<FollowResponse>,
    ) {
        try {
            val followEntity = userService.follow(request.userId, request.targetUserId)
            val response = FollowResponse.newBuilder()
                .setId(followEntity.id)
                .setFollowerId(followEntity.followerId)
                .setFollowingId(followEntity.followingId)
                .setStatus(followEntity.status.name)
                .setCreatedAt(followEntity.createdAt.toString())
                .build()
            responseObserver.onNext(response)
            responseObserver.onCompleted()
        } catch (e: Exception) {
            responseObserver.onError(Status.INTERNAL.withDescription(e.message).asException())
        }
    }

    override fun unfollow(
        request: UnfollowRequest,
        responseObserver: StreamObserver<UnfollowResponse>,
    ) {
        try {
            val success = userService.unfollow(request.userId, request.targetUserId)
            val response = UnfollowResponse.newBuilder()
                .setSuccess(success)
                .build()
            responseObserver.onNext(response)
            responseObserver.onCompleted()
        } catch (e: Exception) {
            responseObserver.onError(Status.INTERNAL.withDescription(e.message).asException())
        }
    }

    override fun isFollowing(
        request: IsFollowingRequest,
        responseObserver: StreamObserver<IsFollowingResponse>,
    ) {
        try {
            val isFollowing = userService.isFollowing(request.userId, request.targetUserId)
            val response = IsFollowingResponse.newBuilder()
                .setIsFollowing(isFollowing)
                .build()
            responseObserver.onNext(response)
            responseObserver.onCompleted()
        } catch (e: Exception) {
            responseObserver.onError(Status.INTERNAL.withDescription(e.message).asException())
        }
    }

    override fun getFollowers(
        request: GetFollowersRequest,
        responseObserver: StreamObserver<GetFollowersResponse>,
    ) {
        try {
            val followers = userService.getFollowers(request.userId, request.limit, request.offset)
            val response = GetFollowersResponse.newBuilder()
                .addAllFollowers(followers.map { it.toProto() })
                .setTotal(userService.getFollowerCount(request.userId))
                .build()
            responseObserver.onNext(response)
            responseObserver.onCompleted()
        } catch (e: Exception) {
            responseObserver.onError(Status.INTERNAL.withDescription(e.message).asException())
        }
    }

    override fun getFollowings(
        request: GetFollowingsRequest,
        responseObserver: StreamObserver<GetFollowingsResponse>,
    ) {
        try {
            val followings = userService.getFollowings(request.userId, request.limit, request.offset)
            val response = GetFollowingsResponse.newBuilder()
                .addAllFollowings(followings.map { it.toProto() })
                .setTotal(userService.getFollowingCount(request.userId))
                .build()
            responseObserver.onNext(response)
            responseObserver.onCompleted()
        } catch (e: Exception) {
            responseObserver.onError(Status.INTERNAL.withDescription(e.message).asException())
        }
    }
}
