## 7. GraphQL 서비스 (gRPC 클라이언트)

**파일 경로:** `/graphql/src/main/kotlin/com/maum/backend/service/user/FollowService.kt`

```kotlin
@Service
class FollowService {

    @GrpcClient("user-grpc")
    private lateinit var userStub: UserServiceGrpc.UserServiceBlockingStub

    fun follow(userId: String, targetUserId: String): FollowResponse {
        val request = FollowRequest.newBuilder()
            .setUserId(userId)
            .setTargetUserId(targetUserId)
            .build()
        return try {
            userStub.follow(request)
        } catch (e: StatusRuntimeException) {
            throw CustomGraphQLException(e.trailers!!, e.status.description)
        }
    }

    fun unfollow(userId: String, targetUserId: String): Boolean {
        val request = UnfollowRequest.newBuilder()
            .setUserId(userId)
            .setTargetUserId(targetUserId)
            .build()
        return try {
            userStub.unfollow(request).success
        } catch (e: StatusRuntimeException) {
            throw CustomGraphQLException(e.trailers!!, e.status.description)
        }
    }

    fun isFollowing(userId: String, targetUserId: String): Boolean {
        val request = IsFollowingRequest.newBuilder()
            .setUserId(userId)
            .setTargetUserId(targetUserId)
            .build()
        return try {
            userStub.isFollowing(request).isFollowing
        } catch (e: StatusRuntimeException) {
            throw CustomGraphQLException(e.trailers!!, e.status.description)
        }
    }

    fun getFollowers(userId: String, limit: Int = 20, offset: Int = 0): FollowList {
        val request = GetFollowersRequest.newBuilder()
            .setUserId(userId)
            .setLimit(limit)
            .setOffset(offset)
            .build()
        return try {
            val response = userStub.getFollowers(request)
            FollowList(response.followersList, response.total)
        } catch (e: StatusRuntimeException) {
            throw CustomGraphQLException(e.trailers!!, e.status.description)
        }
    }

    fun getFollowings(userId: String, limit: Int = 20, offset: Int = 0): FollowList {
        val request = GetFollowingsRequest.newBuilder()
            .setUserId(userId)
            .setLimit(limit)
            .setOffset(offset)
            .build()
        return try {
            val response = userStub.getFollowings(request)
            FollowList(response.followingsList, response.total)
        } catch (e: StatusRuntimeException) {
            throw CustomGraphQLException(e.trailers!!, e.status.description)
        }
    }
}
