        return followService.follow(userId, input.targetUserId)
    }

    @MutationMapping
    @PreAuthorize("hasAuthority('User')")
    fun unfollow(
        @UserId userId: String,
        @Argument targetUserId: String,
    ): Boolean {
        return followService.unfollow(userId, targetUserId)
    }

    @QueryMapping
    @PreAuthorize("hasAuthority('User')")
    fun isFollowing(
        @UserId userId: String,
        @Argument targetUserId: String,
    ): Boolean {
        return followService.isFollowing(userId, targetUserId)
    }

    @QueryMapping
    fun followers(
        @Argument userId: String,
        @Argument limit: Int?,
        @Argument offset: Int?,
    ): FollowList {
        return followService.getFollowers(userId, limit ?: 20, offset ?: 0)
    }

    @QueryMapping
    fun followings(
        @Argument userId: String,
        @Argument limit: Int?,
        @Argument offset: Int?,
    ): FollowList {
        return followService.getFollowings(userId, limit ?: 20, offset ?: 0)
    }

    @QueryMapping
    fun followerCount(@Argument userId: String): Int {
        return followService.getFollowerCount(userId).toInt()
    }

