## 9. 테스트 파일 예상 위치 및 구조

### UserService 팔로우 테스트
**파일 경로:** `/user/src/test/kotlin/com/maum/backend/service/UserServiceFollowTest.kt`

```kotlin
@ExtendWith(MockitoExtension::class)
class UserServiceFollowTest {

    @Mock
    private lateinit var followRepository: FollowRepository

    @Mock
    private lateinit var userRepository: UserRepository

    @InjectMocks
    private lateinit var userService: UserService

    @Test
    fun `should follow user successfully`() {
        // given
        val userId = "user-1"
        val targetUserId = "user-2"
        `when`(userRepository.findById(userId)).thenReturn(UserEntity(...))
        `when`(userRepository.findById(targetUserId)).thenReturn(UserEntity(...))
        `when`(followRepository.findByFollowerIdAndFollowingId(userId, targetUserId)).thenReturn(null)

        // when
        val result = userService.follow(userId, targetUserId)

        // then
        assertThat(result.followerId).isEqualTo(userId)
        assertThat(result.followingId).isEqualTo(targetUserId)
        verify(followRepository).save(any())
    }

    @Test
    fun `should throw when already following`() {
        // given
        val userId = "user-1"
        val targetUserId = "user-2"
        val existing = FollowEntity(followerId = userId, followingId = targetUserId)
        `when`(userRepository.findById(userId)).thenReturn(UserEntity(...))
        `when`(userRepository.findById(targetUserId)).thenReturn(UserEntity(...))
        `when`(followRepository.findByFollowerIdAndFollowingId(userId, targetUserId))
            .thenReturn(existing)

        // when & then
        assertThrows<AlreadyFollowException> {
            userService.follow(userId, targetUserId)
        }
    }

    @Test
    fun `should unfollow successfully`() {
        // given
        val userId = "user-1"
        val targetUserId = "user-2"
        val follow = FollowEntity(followerId = userId, followingId = targetUserId)
        `when`(followRepository.findByFollowerIdAndFollowingId(userId, targetUserId))
            .thenReturn(follow)

        // when
        val result = userService.unfollow(userId, targetUserId)

        // then
        assertThat(result).isTrue()
        verify(followRepository).delete(follow)
    }
}
```

