CREATE TABLE `maum`.`follow` (
  `id` VARCHAR(36) NOT NULL COMMENT 'UUID',
  `follower_id` VARCHAR(36) NOT NULL COMMENT '팔로워 사용자 ID',
  `following_id` VARCHAR(36) NOT NULL COMMENT '팔로잉 사용자 ID',
  `status` VARCHAR(20) NOT NULL DEFAULT 'ACTIVE' COMMENT '상태 (ACTIVE, BLOCKED, HIDDEN)',
  `created_at` DATETIME(3) NOT NULL DEFAULT CURRENT_TIMESTAMP(3) COMMENT '생성일',
  `updated_at` DATETIME(3) NOT NULL DEFAULT CURRENT_TIMESTAMP(3) ON UPDATE CURRENT_TIMESTAMP(3) COMMENT '수정일',
  PRIMARY KEY (`id`),
  UNIQUE KEY `uk_follow_follower_following` (`follower_id`, `following_id`),
  KEY `idx_follower_id` (`follower_id`),
  KEY `idx_following_id` (`following_id`),
  CONSTRAINT `fk_follow_follower` FOREIGN KEY (`follower_id`) REFERENCES `user` (`id`) ON DELETE CASCADE,
  CONSTRAINT `fk_follow_following` FOREIGN KEY (`following_id`) REFERENCES `user` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='팔로우 관계';
